            "*, coach_specialties(specialty)"
        ).eq("id", coach_id).eq("role", "coach").single().execute()

        coach = response.data
        if coach:
            coach["specialties"] = [s["specialty"] for s in coach.get("coach_specialties", [])]
        return coach
    except Exception as e:
        print(f"Erreur récupération coach: {e}")
