.results-section {
  padding: 60px 20px;
  background: #f8f9fa;
  min-height: 400px;
}

.results-container {
  max-width: 1200px;
  margin: 0 auto;
}

.filters-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
  flex-wrap: wrap;
  gap: 15px;
}

.filters-left {
  display: flex;
  gap: 10px;
