}

.filter-btn.active {
  background: #e50914;
  color: white;
  border-color: #e50914;
}

.filters-right {
  display: flex;
  align-items: center;
  gap: 10px;
}

.filters-right label {
  font-weight: 500;
  font-size: 14px;
}

.filters-right select {
  padding: 10px 15px;
  border: 1px solid #ddd;
  border-radius: 8px;
  background: white;
